    // صحيح: x = cos(angle), y = sin(angle)
    // خاطئ: x = sin(angle), y = cos(angle) — يدور عكس الاتجاه المعتاد!
    double x = std::cos(angle);
    double y = std::sin(angle);
    return (x == 1.0 && y == 0.0) ? 1 : 0;
}

