#include <stdexcept>

struct Base { virtual ~Base() = default; };
struct Derived : Base { int x = 42; };

int main() {
    Base b;
    // مع المؤشر: لا يُرمى bad_cast
    Derived* d = dynamic_cast<Derived*>(&b);
