    return 0;
}

#include <stdexcept>

struct Base { /* نسيان virtual! */ };
struct Derived : Base { int x = 42; };

int main() {
    Base b;
    // dynamic_cast<Derived*>(&b) يُرجع nullptr صامتًا
    // لأن Base ليست polymorphic (لا تملك virtual)
    Derived* d = dynamic_cast<Derived*>(&b);
    return d == nullptr ? 1 : 0;
}

