#include <cfloat>

int main() {
    // underflow_error ≠ underflow العائم
    // underflow العائم = قيمة أصغر من أصغر قيمة ممكنة (تتحول لـ subnormal أو صفر)
    // underflow_error = استثناء يُرمى يدويًا أو من stol
    float f = 1e-40f;
    // f تصبح subnormal لا يُرمى شيء
    return f > 0 ? 1 : 0;
}

