#include <iostream>
#include <string>

int main() {
    int age;
    std::string name;

    std::cout << "العمر: ";
    std::cin >> age;

    // cin >> ترك حرف \n في التيار
    // بدون ignore: getline ستقرأ سطرًا فارغًا فورًا
    std::cin.ignore(std::numeric_limits<std::streamsize>::max(), '\n');

    std::cout << "الاسم: ";
    std::getline(std::cin, name);

    std::cout << name << " (" << age << ")" << '\n';
}

#include <iostream>

int main() {
    int x;
    std::cout << "أدخل عددًا: ";
    std::cin >> x; // أدخل "abc" — cin في حالة خطأ

    // ❌ بدون clear: كل القراءات التالية ستفشل تلقائيًا
    // std::cin >> x; // فشل صامت!

    // ✅ أعد التعيين ثم تجاهل الإدخال الخاطئ
    std::cin.clear(); // يُزيل حالة الخطأ
    std::cin.ignore(std::numeric_limits<std::streamsize>::max(), '\n');

    std::cin >> x; // الآن يمكن القراءة مجددًا
}

