int main() {
    std::vector<std::string> names = {"alice", "bob", "charlie"};
    std::vector<std::string> upper;
    upper.reserve(names.size());

    std::transform(names.begin(), names.end(), std::back_inserter(upper),
        [](const std::string& s) {
            std::string result = s;
