#include <algorithm>
#include <vector>
#include <iostream>

int main() {
    std::vector<int> v = {1, 2, 3, 4, 5};
    std::vector<int> result;
    result.resize(v.size());

    // transform: يُطبق دالة ويكتب النتائج في نطاق آخر
    std::transform(v.begin(), v.end(), result.begin(),
        [](int x) { return x * 2; });
    // result = {2, 4, 6, 8, 10} — الأصل لم يتغير

    // for_each: يُنفذ دالة على كل عنصر لكنه لا يكتب في مكان آخر
    std::for_each(v.begin(), v.end(), [](int& x) {
        x *= 2;
    });
    // v = {2, 4, 6, 8, 10} — التعديل مباشر في الأصل
}

