void flexible_lock() {
    // unique_lock: أثقل قليلًا لكنه يوفر مرونة
    std::unique_lock<std::mutex> lock(mtx, std::defer_lock);
    // defer_lock: لا يُقفل فوريًا — يمكنك التحكم متى تقفل

    lock.lock();
    // ... قسم حرج ...
    lock.unlock();
    // ... عمل لا يحتاج قفل ...
