#include <algorithm>
#include <vector>

int main() {
    std::vector<int> src = {1, 2, 3, 4, 5};
    std::vector<int> dst;

    std::remove_copy_if(src.begin(), src.end(), std::back_inserter(dst),
        [](int x) { return x % 2 == 0; });
    // dst = {1, 3, 5}
    // src لا تزال {1, 2, 3, 4, 5}

    auto new_end = std::remove_if(src.begin(), src.end(), [](int x) { return x % 2 == 0; });
    src.erase(new_end, src.end());
    // الآن src نفسها أصبحت {1, 3, 5}
}

