template<typename T>
T clamp_zero_to_one(T x) {
    static_assert(std::is_arithmetic_v<T>);
    if (x < static_cast<T>(0)) return static_cast<T>(0);
    if (x > static_cast<T>(1)) return static_cast<T>(1);
    return x;
}

