class NonNegativeCounter {
public:
    explicit NonNegativeCounter(int value) : value_(value < 0 ? 0 : value) {}

    void decrement() {
        if (value_ > 0) {
            --value_;
        }
    }

    int value() const {
        return value_;
    }

private:
    int value_{};
};

int main() {
    NonNegativeCounter counter(2);
    counter.decrement();
    counter.decrement();
    counter.decrement();
    return counter.value();
}

#include <cstdio>

class FileGuard {
public:
    explicit FileGuard(const char* path)
        : file_(std::fopen(path, "w")) {}

    ~FileGuard() {
        if (file_) {
            std::fclose(file_);
        }
    }

    std::FILE* get() const {
        return file_;
    }

private:
    std::FILE* file_{};
};

int main() {
    FileGuard file("log.txt");
    return file.get() ? 0 : 1;
}
